const ethers = require('ethers');

const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

const ERC20_ABI = [
  // Some parts of the ABI
  "function balanceOf(address owner) view returns (uint256)",
  "function transfer(address to, uint256 amount)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function allowance(address owner, address spender) view returns (uint256)"
];

const DEX_ABI = [
  // Some parts of the ABI
  "function swapTokens(address inputToken, address outputToken, uint256 amountIn, uint256 amountOutMin, address to)"
];

const MAX_UINT256 = ethers.constants.MaxUint256;

async function approveToken(tokenAddress, dexAddress) {
  const tokenContract = new ethers.Contract(tokenAddress, ERC20_ABI, signer);
  const allowance = await tokenContract.allowance(signer.getAddress(), dexAddress);

  if (allowance.lt(MAX_UINT256)) {
    const approveTx = await tokenContract.approve(dexAddress, MAX_UINT256);
    await approveTx.wait();
  }
}

async function swapTokens(dexAddress, inputToken, outputToken, amountIn, amountOutMin) {
  const dexContract = new ethers.Contract(dexAddress, DEX_ABI, signer);
  const swapTx = await dexContract.swapTokens(inputToken, outputToken, amountIn, amountOutMin, signer.getAddress());
  await swapTx.wait();
}

